{
var seed = GetInt(parameters, "seed", context.Seed);
var scale = GetFloat(parameters, "scale", 0.15f);
var wallThick = GetFloat(parameters, "wallThickness", 0.15f);
var bevel = GetFloat(parameters, "bevel", 0.3f);
var innerColor = GetColor(parameters, "innerColor", System.Windows.Media.Color.FromRgb(220, 180, 80));
var wallColor = GetColor(parameters, "wallColor", System.Windows.Media.Color.FromRgb(100, 70, 30));
var invert = GetBool(parameters, "invert", false);

var size = context.TileSize;
var buffer = new PixelBuffer(size, size);

var iR = innerColor.R / 255f; var iG = innerColor.G / 255f; var iB = innerColor.B / 255f;
var wR = wallColor.R / 255f; var wG = wallColor.G / 255f; var wB = wallColor.B / 255f;

// Hexagonal grid constants
var sqrt3 = 1.7320508f;
var hX = scale * 1.5f;
var hY = scale * sqrt3;

buffer.ParallelForEachPixel((x, y) =>
{
    var u = (x + 0.5f) / size;
    var v = (y + 0.5f) / size;

    // Convert to hex grid coordinates
    var q = u / hX;
    var r2 = v / hY - q * 0.5f;

    // Round to nearest hex center
    var qr = MathF.Round(q);
    var rr = MathF.Round(r2);

    var dq = q - qr;
    var dr = r2 - rr;

    // Correct for the skewed grid
    if (MathF.Abs(dq) + MathF.Abs(dr) > 0.5f)
    {
        var dqr = -MathF.Sign(dq);
        var drr = -MathF.Sign(dr);
        if (MathF.Abs(dqr) < MathF.Abs(drr))
            qr += dqr * 0.5f;
        else
            rr += drr * 0.5f;
    }

    // Distance to nearest hex center in hex-space
    var distQ = u / hX - qr;
    var distR = v / hY - qr * 0.5f - rr;

    // Convert to Cartesian distance
    var cx = distQ * hX;
    var cy = distR * hY;
    var dist = MathF.Sqrt(cx * cx + cy * cy);

    // Distance to hex edge (approximate)
    var hexRadius = scale;
    var edgeDist = (hexRadius - dist) / hexRadius;

    // Per-hex hash for color variation
    var hashVal = HashToUnit((int)(qr * 1000 + rr), seed, 999);

    // Determine if inside cell or wall
    float r, g, b;
    if (edgeDist > wallThick)
    {
        // Inside cell — inner color with slight variation
        var var_ = (hashVal - 0.5f) * 0.08f;
        r = Math.Clamp(iR + var_, 0f, 1f);
        g = Math.Clamp(iG + var_ * 0.8f, 0f, 1f);
        b = Math.Clamp(iB + var_ * 0.6f, 0f, 1f);

        // Bevel shading near edges
        if (bevel > 0f && edgeDist < wallThick + scale * bevel * 0.3f)
        {
            var bevelFactor = (edgeDist - wallThick) / (scale * bevel * 0.3f);
            bevelFactor = Math.Clamp(bevelFactor, 0f, 1f);
            r = r * (1f - bevelFactor * 0.2f);
            g = g * (1f - bevelFactor * 0.2f);
            b = b * (1f - bevelFactor * 0.15f);
        }
    }
    else
    {
        // Wall
        r = wR; g = wG; b = wB;
    }

    if (invert) { r = 1f - r; g = 1f - g; b = 1f - b; }

    buffer.SetPixel(x, y, Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), 1f);
});

return buffer;
}
